// Giá trong Sheet đã bao gồm VAT 8%. Để tổng đơn khớp đúng với hóa đơn VAT
// thật (kế toán tính: tiền hàng trước VAT theo từng dòng → cộng lại → tính
// VAT 1 lần trên tổng), KHÔNG được nhân thẳng giá-có-VAT với số lượng rồi
// cộng (cách đó làm tròn VAT theo từng đơn vị, cộng dồn sai lệch vài đồng so
// với hóa đơn thật). Phải tách giá trước VAT theo từng dòng trước.
var VAT_RATE=0.08;
function giaTruocVAT(giaCoVAT){ return Math.round(giaCoVAT/(1+VAT_RATE)); }
// Tính tiền hàng trước VAT cho 1 dòng (đơn giá có VAT, làm tròn về giá trước
// VAT rồi mới nhân số lượng — đúng cách hóa đơn tính từng dòng).
// Làm tròn về đồng nguyên — số lượng m² có thể lẻ (vd 2,5 m²) nên thành tiền
// dòng có thể ra số lẻ, phải làm tròn ngay để không lộ số thập phân khi hiển thị.
function tienHangTruocVAT(giaCoVAT, qty){ return Math.round(giaTruocVAT(giaCoVAT)*(parseFloat(qty)||0)); }
// Từ tổng tiền hàng trước VAT của cả đơn, tính VAT 1 lần + tổng thanh toán
// (đúng cách hóa đơn VAT chỉ tính thuế 1 lần trên tổng, không cộng VAT từng dòng).
function tinhVATvaTongThanhToan(tongTienHangTruocVAT){
  tongTienHangTruocVAT=Math.round(tongTienHangTruocVAT);
  var vat=Math.round(tongTienHangTruocVAT*VAT_RATE);
  return {truocVAT:tongTienHangTruocVAT, vat:vat, tong:tongTienHangTruocVAT+vat};
}
