function normMa(s){ return String(s||'').trim().toUpperCase().replace(/[^A-Z0-9]/g,''); }
function timAnh(ma){
  if(imgStore[ma]) return imgStore[ma];
  var nm=normMa(ma);
  var k=Object.keys(imgStore).find(function(key){ return normMa(key)===nm; });
  return k?imgStore[k]:null;
}
function timAnhMulti(ma){
  if(imgStoreMulti[ma] && imgStoreMulti[ma].length) return imgStoreMulti[ma];
  var nm=normMa(ma);
  var k=Object.keys(imgStoreMulti).find(function(key){ return normMa(key)===nm; });
  if(k && imgStoreMulti[k] && imgStoreMulti[k].length) return imgStoreMulti[k];
  var single=timAnh(ma);
  return single?[single]:[];
}

// Fetch bảng giá từ Google Sheet (JSONP)
// Gọi khi app mở — cập nhật DATA từ Sheet, không cần sửa code
function fetchGiaFromSheet(){
  var APPS_URL='https://script.google.com/macros/s/AKfycbyrO8symCYOkWsGG0nRWPF7gpndC3mzEVUk15UvWrA0O81ZUumW-kX_gEOZhtCJ34bMVQ/exec';
  var loais = ['gach','ngoi','keo','kinh'];
  var loaded = 0;

  loais.forEach(function(loai){
    window['_onGia_'+loai] = function(res){
      try{
        if(!res||!res.data||!res.data.length) return;
        var rows = res.data;
        
        if(loai==='gach'){
          // Cập nhật giá vào DATA array
          rows.forEach(function(row){
            var ma = String(row.ma||'').trim();
            if(!ma) return;
            function pg(v){return parseFloat(String(v||'0').replace(/\./g,'').replace(/,/g,'.'))||0;}
            var le=pg(row.le), nhan=pg(row.nhan), giao=pg(row.giao);
            var nsSheet=pg(row.ns), nsCT1=pg(row.ns_ct1);
            var ns = nsSheet>0 ? nsSheet : nsCT1>0 ? Math.round(nsCT1*0.95) : Math.round(nhan*0.95);
            var gs = pg(row.gs)||giao;

            // Tìm trong DATA hiện tại
            var p = DATA.find(function(x){return x.ma===ma;});
            if(p){
              // Mã đã có → chỉ cập nhật nếu giá > 0 (tránh ghi đè bằng 0 khi Sheet lỗi)
              if(le>0)   p.le=le;
              if(nhan>0) p.nhan=nhan;
              if(giao>0) p.giao=giao;
              if(ns>0)   p.ns=ns;
              if(gs>0)   p.gs=gs;
            } else {
              // Mã MỚI trong Sheet → thêm vào DATA
              DATA.push({
                ma:ma, kc:String(row.kc||''), cat:String(row.cat||'').toLowerCase(),
                gio:String(row.gio||''), ten:String(row.ten||ma),
                le:le, nhan:nhan, giao:giao, ns:ns, gs:gs
              });
            }
          });
          console.log('✅ Cập nhật giá gạch từ Sheet: '+rows.length+' mã (bao gồm mã mới)');
        }
        else if(loai==='ngoi'){
          rows.forEach(function(row){
            var ma = String(row.ma||'').trim();
            var p = NGOI.find(function(x){return x.ma===ma;});
            if(p){
              function pg2(v){return parseFloat(String(v||'0').replace(/\./g,'').replace(/,/g,'.'))||0;}
              var _le=pg2(row.le),_nhan=pg2(row.nhan),_nhan2=pg2(row.nhan2);
              var _giao=pg2(row.giao),_giao2=pg2(row.giao2);
              // Guard > 0: không ghi đè nếu Sheet trả về 0
              if(_le>0)    p.le=_le;
              if(_nhan>0)  p.nhan=_nhan;
              if(_nhan2>0) p.nhan2=_nhan2;
              if(_giao>0)  p.giao=_giao;
              if(_giao2>0) p.giao2=_giao2;
              var nsNgoi = pg2(row.ns);
              p.ns = nsNgoi > 0 ? nsNgoi : Math.round(p.nhan * 0.90);
              p.gs = pg2(row.gs) || p.giao;
            }
          });
          console.log('✅ Cập nhật giá ngói từ Sheet: '+rows.length+' mã');
        }
        else if(loai==='keo'){
          rows.forEach(function(row){
            var ma = String(row.ma||'').trim();
            var p = KEO.find(function(x){return x.ma===ma;});
            if(p){
              function pgKeo(v){return parseFloat(String(v||"0").replace(/\./g,"").replace(/,/g,"."))||0;}
              var _le=pgKeo(row.le),_nhan=pgKeo(row.nhan),_nhan2=pgKeo(row.nhan2);
              var _giao=pgKeo(row.giao),_giao2=pgKeo(row.giao2);
              if(_le>0)    p.le=_le;
              if(_nhan>0)  p.nhan=_nhan;
              if(_nhan2>0) p.nhan2=_nhan2;
              if(_giao>0)  p.giao=_giao;
              if(_giao2>0) p.giao2=_giao2;
            }
          });
          console.log('✅ Cập nhật giá keo từ Sheet: '+rows.length+' mã');
        }
        else if(loai==='kinh'){
          rows.forEach(function(row){
            var ma = String(row.ma||'').trim();
            var p = KINH.find(function(x){return x.ma===ma;});
            if(p){
              function pgK(v){return parseFloat(String(v||"0").replace(/\./g,"").replace(/,/g,"."))||0;}
              var _le=pgK(row.le),_nhan=pgK(row.nhan),_nhan2=pgK(row.nhan2),_nhan3=pgK(row.nhan3);
              var _giao=pgK(row.giao),_giao2=pgK(row.giao2),_giao3=pgK(row.giao3);
              if(_le>0)    p.le=_le;
              if(_nhan>0)  p.nhan=_nhan;
              if(_nhan2>0) p.nhan2=_nhan2;
              if(_nhan3>0) p.nhan3=_nhan3;
              if(_giao>0)  p.giao=_giao;
              if(_giao2>0) p.giao2=_giao2;
              if(_giao3>0) p.giao3=_giao3;
            }
          });
          console.log('✅ Cập nhật giá kính từ Sheet: '+rows.length+' mã');
        }
        
        loaded++;
        if(loaded===loais.length){
          // Render lại sau khi cập nhật xong
          // Cập nhật badge
          var badge = document.getElementById('gia-source-badge');
          if(badge){
            badge.textContent = '✅ Giá Sheet';
            badge.style.background = '#E8F5E9';
            badge.style.color = '#1B5E20';
          }
          render();
          renderSale();
          console.log('🎉 Đã đồng bộ giá từ Sheet xong!');
        }
      }catch(e){ console.log('Lỗi parse giá '+loai+':', e.message); }
      var s=document.getElementById('_gia_script_'+loai);
      if(s) s.remove();
    };
    
    var old=document.getElementById('_gia_script_'+loai);
    if(old) old.remove();
    var s=document.createElement('script');
    s.id='_gia_script_'+loai;
    s.src=APPS_URL+'?action=getGia&loai='+loai+'&callback=_onGia_'+loai;
    s.onerror=function(){
      console.log('⚠️ Không tải được giá '+loai+' từ Sheet — dùng giá trong app');
      s.remove();
    };
    document.head.appendChild(s);
  });
}


// Fetch ảnh từ Google Sheet khi đăng nhập (dùng script tag để tránh CORS)
function fetchImagesFromSheet(){
  var APPS_URL='https://script.google.com/macros/s/AKfycbyrO8symCYOkWsGG0nRWPF7gpndC3mzEVUk15UvWrA0O81ZUumW-kX_gEOZhtCJ34bMVQ/exec';

  // Dùng JSONP: inject script tag để bypass CORS
  window._onImgData = function(data){
    try{
      if(data && data.images){
        var map=data.images, count=0;
        Object.keys(map).forEach(function(ma){
          if(map[ma]){ imgStore[ma]=map[ma]; count++; }
        });
        // Build multi: data.imagesMulti[ma] = [url1,url2,...]
        if(data.imagesMulti){
          Object.keys(data.imagesMulti).forEach(function(ma){
            imgStoreMulti[ma]=data.imagesMulti[ma];
          });
          try{ localStorage.setItem('dt_imgs_multi', JSON.stringify(imgStoreMulti)); }catch(e){}
        }
        try{ localStorage.setItem('dt_imgs', JSON.stringify(imgStore)); }catch(e){}
        if(curP_ma) loadImg(curP_ma);
        renderSale(); // refresh ảnh trong sale grid
        console.log('✅ Đã tải '+count+' ảnh từ Sheet');
      }
    }catch(e){ console.log('Lỗi parse ảnh:', e); }
    // Xóa script tag sau khi xong
    var old=document.getElementById('_img_script');
    if(old) old.remove();
  };

  // Xóa script cũ nếu có
  var old=document.getElementById('_img_script');
  if(old) old.remove();

  var s=document.createElement('script');
  s.id='_img_script';
  s.src=APPS_URL+'?action=getImages&callback=_onImgData';
  s.onerror=function(){
    console.log('⚠️ Không kết nối được Sheet – dùng cache localStorage');
    s.remove();
  };
  document.head.appendChild(s);
}
