function showDP(ma){
  var p=DATA.find(function(x){return x.ma===ma;}); if(!p) return;
  curP_ma=ma;
  document.getElementById('dp-ma').textContent=p.ma;
  document.getElementById('dp-kc').textContent='Kích cỡ: '+p.kc+(p.gio?' · '+p.gio+(p.gio==='★'?' Chiến lược':' Chủ lực'):'');
  // Quy cách: số viên/thùng, kg/thùng
  var qcEl = document.getElementById('dp-quycach');
  if(qcEl){
    var qc = getQuyCach(p.kc, p.cat);
    if(qc){
      qcEl.style.display='block';
      qcEl.textContent = '📦 '+qc.vien+' viên/thùng · '+qc.m2+'m²/thùng'+(qc.kg?' · '+qc.kg+'kg/thùng':'');
    } else {
      qcEl.style.display='none';
    }
  }
  document.getElementById('dp-le').textContent=fmt(p.le);
  // SP từ CT1/CT2 (đang Sale/Xả kho): ô đầu popup phải hiện ĐÚNG giá sale,
  // không phải giá thường — dù mã đó vừa có giá thường vừa có giá sale
  // (trước đây ưu tiên giá thường khi >0 nên hiện sai cho mã trùng cả 2).
  var isSaleItem = p._fromCT==='CT1' || p._fromCT==='CT2';
  var dispNhan = (isSaleItem && p.ns>0) ? p.ns : (p.nhan > 0 ? p.nhan : (p.ns || 0));
  var dispGiao = (isSaleItem && p.gs>0) ? p.gs : (p.giao > 0 ? p.giao : (p.gs || 0));
  document.getElementById('dp-nhan').textContent = fmt(dispNhan);
  document.getElementById('dp-giao').textContent = fmt(dispGiao);
  // Cập nhật label GIÁ ĐẠI LÝ → GIÁ SALE nếu là SP từ CT1/CT2
  var giaDlLabel = document.getElementById('dp-gia-dl-label');
  if(giaDlLabel){
    if(p._fromCT==='CT1') giaDlLabel.innerHTML='🔥 GIÁ SALE THÁNG <span style="font-size:10px;background:#E8F5E9;color:#1B5E20;padding:1px 6px;border-radius:4px">CT1</span>';
    else if(p._fromCT==='CT2') giaDlLabel.innerHTML='📦 GIÁ XẢ KHO <span style="font-size:10px;background:#FFF3E0;color:#E65100;padding:1px 6px;border-radius:4px">CT2</span>';
    else giaDlLabel.textContent='GIÁ ĐẠI LÝ';
  }
  // Tra giá sale từ CT1_DATA / CT2_DATA (nếu đã load)
  var saleInfo = CT1_DATA.find(function(x){return x.ma===ma;})
               || CT2_DATA.find(function(x){return x.ma===ma;});
  var ns_sale = saleInfo ? (saleInfo.ns||0) : (p.ns||0);
  var gs_sale = saleInfo ? (saleInfo.gs||0) : (p.gs||0);
  var loai_sale = saleInfo ? saleInfo.loai_sale : null;
  var hasSale = ns_sale>0 || gs_sale>0;
  var saleSec = document.getElementById('dp-sale-section');
  saleSec.style.display = hasSale ? 'block' : 'none';
  if(hasSale){
    document.getElementById('dp-ns').textContent=fmt(ns_sale);
    document.getElementById('dp-gs').textContent=fmt(gs_sale);
    var base=p.nhan||p.giao; var saleP=ns_sale||gs_sale;
    if(base&&saleP){ var save=base-saleP; var pct=Math.round(save/base*100);
      document.getElementById('dp-save').textContent='Tiết kiệm '+save.toLocaleString('vi-VN')+'đ/m² (giảm '+pct+'%)'; }
    // Hiện badge loại sale
    var badgeEl = document.getElementById('dp-sale-badge');
    if(badgeEl){
      badgeEl.style.display='inline';
      if(loai_sale==='ct1') { badgeEl.textContent='🗓️ Sale tháng'; badgeEl.style.cssText='display:inline;font-size:10px;background:#E8F5E9;color:#2E7D32;padding:2px 6px;border-radius:4px;margin-left:6px'; }
      else if(loai_sale==='ct2') { badgeEl.textContent='📦 Xả kho'; badgeEl.style.cssText='display:inline;font-size:10px;background:#FFF3E0;color:#E65100;padding:2px 6px;border-radius:4px;margin-left:6px'; }
      else badgeEl.style.display='none';
    }
  } else {
    var badgeEl2 = document.getElementById('dp-sale-badge');
    if(badgeEl2) badgeEl2.style.display='none';
  }
  document.getElementById('dp-sell').value=p.nhan>0?Math.round(p.nhan*1.07):'';
  document.getElementById('dp').style.display='block';
  var isDesk=(window.innerWidth||document.documentElement.clientWidth||0)>=768;
  if(isDesk) document.body.classList.add('dp-open');
  else { var bd=document.getElementById('dp-backdrop'); if(bd) bd.classList.add('on'); }
  if(document.getElementById('dp-scroll')) document.getElementById('dp-scroll').scrollTop=0;
  calcM();
  // Reset qty input về m² mặc định
  dpUnit='m2';
  var qtyInp=document.getElementById('dp-qty-input');
  if(qtyInp) qtyInp.value=1;
  setTimeout(function(){ setDpUnit('m2'); },10);
  loadImg(ma);
}
function closeDp(){
  document.getElementById('dp').style.display='none';
  document.body.classList.remove('dp-open');
  var bd=document.getElementById('dp-backdrop'); if(bd) bd.classList.remove('on');
  if((window.innerWidth||document.documentElement.clientWidth||0)>=768) renderDon();
}
function calcM(){
  var p=DATA.find(function(x){return x.ma===curP_ma;}); if(!p) return;
  var sell=parseInt(document.getElementById('dp-sell').value)||0;
  var cost=p.ns||p.nhan||0; var m=document.getElementById('dp-margin');
  if(sell>0&&cost>0){ var pr=sell-cost; var pct=Math.round(pr/sell*100);
    m.textContent=(pr>=0?'+':'')+pr.toLocaleString('vi-VN')+'đ ('+pct+'%)';
    m.style.color=pr>=0?'#388E3C':'#C0232A'; } else m.textContent='–';
}

