function addToDonKinh(ma){
  var p=KINH.find(function(x){return x.ma===ma;}); if(!p) return;
  var exist=donItems.find(function(x){return x.ma===ma;});
  if(exist){ exist.qty++; }
  else {
    donItems.push({
      ma:p.ma, ten:p.ten, kc:p.kc, unit:'thùng', loai:'kinh',
      le:p.le||0,
      nhan:p.nhan||0,   // giá ≤20 thùng
      giao:p.giao||0,
      nhan2:p.nhan2||0, // giá 21-49 thùng
      giao2:p.giao2||0,
      nhan3:p.nhan3||0, // giá ≥50 thùng
      giao3:p.giao3||0,
      ns:0, gs:0, qty:1
    });
  }
  updateDonBadge();
  updateDonBadge();
  calcAndShowTotals();
  showToast('✓ Đã thêm gạch kính vào đơn!');
}

