function driveLink(url){
  if(!url) return '';
  // Extract file ID from various Drive URL formats
  var m = url.match(/\/d\/([a-zA-Z0-9_-]+)/);
  if(m) return 'https://lh3.googleusercontent.com/d/'+m[1];
  // Already direct format
  if(url.includes('googleusercontent.com')) return url;
  return url;
}

var curImgIdx = 0;
var curImgList = [];

function loadImg(ma){
  var wrap = document.getElementById('dp-img-wrap');

  // Lấy tất cả ảnh của mã SP (multi hoặc single, khớp linh hoạt hoa/thường)
  curImgList = timAnhMulti(ma);

  curImgIdx = 0;

  if(curImgList.length > 0){
    wrap.style.display = 'block';
    renderDpImg();
  } else {
    wrap.style.display = 'none';
    document.getElementById('dp-img-counter').style.display = 'none';
    document.getElementById('dp-img-dots').innerHTML = '';
  }
}

function convertImgUrl(url){
  if(!url) return '';
  // Google Drive: /file/d/ID → googleusercontent
  var m1 = url.match(/\/d\/([a-zA-Z0-9_-]{20,})/);
  if(m1) return 'https://lh3.googleusercontent.com/d/'+m1[1];
  // Google Photos: photos.app.goo.gl → không thể embed trực tiếp
  // Thử dùng thumbnail API
  if(url.indexOf('photos.app.goo.gl') >= 0 || url.indexOf('photo.google.com') >= 0){
    return url; // Giữ nguyên, sẽ fallback
  }
  return url;
}

function renderDpImg(){
  var img     = document.getElementById('dp-img');
  var prev    = document.getElementById('dp-img-prev');
  var next    = document.getElementById('dp-img-next');
  var dots    = document.getElementById('dp-img-dots');
  var counter = document.getElementById('dp-img-counter');

  if(!curImgList.length) return;

  var url = convertImgUrl(curImgList[curImgIdx]);
  img.src = url;
  img.onerror = function(){
    // Nếu load lỗi - thử URL gốc
    if(this.src !== curImgList[curImgIdx]){
      this.src = curImgList[curImgIdx];
    } else {
      // Hiện placeholder
      this.style.display='none';
      var ph = document.getElementById('dp-img-placeholder');
      if(!ph){
        ph = document.createElement('div');
        ph.id = 'dp-img-placeholder';
        ph.style.cssText='padding:30px;text-align:center;color:#888;font-size:12px';
        ph.innerHTML='⚠️ Không load được ảnh<br><small>Dùng link Drive thay vì Photos</small>';
        this.parentNode.appendChild(ph);
      }
    }
  };
  img.style.display='block';
  var ph=document.getElementById('dp-img-placeholder');
  if(ph) ph.remove();

  var multi = curImgList.length > 1;
  prev.style.display    = multi ? 'block' : 'none';
  next.style.display    = multi ? 'block' : 'none';
  counter.style.display = multi ? 'block' : 'none';
  counter.textContent   = (curImgIdx+1)+'/'+curImgList.length;

  // Render dots
  dots.innerHTML = '';
  if(multi){
    curImgList.forEach(function(_,i){
      var d = document.createElement('span');
      d.style.cssText = 'width:'+(i===curImgIdx?'14':'6')+'px;height:6px;border-radius:3px;'
        +'background:'+(i===curImgIdx?'#fff':'rgba(255,255,255,.5)')+';transition:.2s';
      dots.appendChild(d);
    });
  }
}

function slideImg(dir){
  if(!curImgList.length) return;
  curImgIdx = (curImgIdx + dir + curImgList.length) % curImgList.length;
  renderDpImg();
}

