// ===== CHIA SẺ NHIỀU ẢNH SẢN PHẨM (qua Zalo/app khác trên điện thoại) =====
// Dùng Web Share API (navigator.share với files) để gửi thẳng nhiều ảnh +
// tên sản phẩm sang Zalo/Messenger/... giống nút Share gốc trên điện thoại.
// Nếu máy/trình duyệt không hỗ trợ (thường là máy tính), tự mở từng ảnh ở
// tab mới để nhân viên bấm giữ lưu ảnh rồi tự gửi qua Zalo.
function _thucHienChiaSe(urls, ma, tenSP){
  function moTabDuPhong(){
    urls.slice(0,5).forEach(function(u){ window.open(convertImgUrl(u),'_blank'); });
    showToast('📷 Đã mở '+Math.min(urls.length,5)+' ảnh ở tab mới — bấm giữ ảnh để lưu, rồi gửi qua Zalo');
  }
  function forcePaint(){
    // Fix blank screen sau khi trở về từ share sheet
    requestAnimationFrame(function(){
      document.body.style.opacity='0.99';
      requestAnimationFrame(function(){ document.body.style.opacity=''; });
    });
  }
  if(!(navigator.share && navigator.canShare)){ moTabDuPhong(); return; }
  showToast('⏳ Đang chuẩn bị ảnh...');
  Promise.all(urls.map(function(u){
    return fetch(convertImgUrl(u)).then(function(res){
      if(!res.ok) throw new Error('fetch fail');
      return res.blob();
    });
  })).then(function(blobs){
    var files=blobs.map(function(b,i){
      return new File([b],(ma||'anh')+'_'+(i+1)+'.jpg',{type:b.type||'image/jpeg'});
    });
    if(navigator.canShare({files:files})){
      return navigator.share({files:files,title:tenSP||ma,text:tenSP||ma}).then(forcePaint);
    }
    throw new Error('canShare false');
  }).catch(function(err){
    forcePaint();
    if(err&&err.name==='AbortError') return;
    console.log('Web Share thất bại, dùng tab dự phòng:',err);
    moTabDuPhong();
  });
}

function chiaSeAnhSanPham(ma, tenSP){
  var imgs=timAnhMulti(ma);
  if(!imgs.length){ alert('Sản phẩm này chưa có ảnh trong Sheet!'); return; }
  // Nếu chỉ 1 ảnh → chia sẻ luôn
  if(imgs.length===1){ _thucHienChiaSe(imgs,ma,tenSP); return; }
  // Nhiều ảnh → modal chọn ảnh
  var ov=document.createElement('div');
  ov.id='img-picker-ov';
  ov.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9999;display:flex;align-items:flex-end;justify-content:center';
  var sel=imgs.map(function(){ return true; }); // mặc định chọn tất
  function buildUI(){
    var nSel=sel.filter(Boolean).length;
    ov.innerHTML='<div style="background:var(--bg1);border-radius:16px 16px 0 0;width:100%;max-width:480px;max-height:80vh;display:flex;flex-direction:column;overflow:hidden">'
      +'<div style="display:flex;align-items:center;justify-content:space-between;padding:14px 16px 10px;border-bottom:1px solid var(--bd)">'
      +'<span style="font-size:14px;font-weight:700;color:var(--t1)">Chọn ảnh chia sẻ</span>'
      +'<button id="ipc-close" style="border:none;background:none;font-size:20px;cursor:pointer;color:var(--t2);padding:0 4px">×</button>'
      +'</div>'
      +'<div style="display:flex;gap:8px;padding:8px 16px;border-bottom:1px solid var(--bd)">'
      +'<button id="ipc-all" style="flex:1;padding:6px;border-radius:8px;border:1px solid var(--bd);background:'+(nSel===imgs.length?'var(--red)':'var(--bg2)')+';color:'+(nSel===imgs.length?'#fff':'var(--t1)')+';font-size:12px;font-weight:600;cursor:pointer">Chọn tất cả</button>'
      +'<button id="ipc-none" style="flex:1;padding:6px;border-radius:8px;border:1px solid var(--bd);background:var(--bg2);color:var(--t1);font-size:12px;font-weight:600;cursor:pointer">Bỏ chọn</button>'
      +'</div>'
      +'<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px;padding:10px 12px;overflow-y:auto;flex:1">'
      +imgs.map(function(u,i){
        var ch=sel[i];
        return '<div data-i="'+i+'" style="position:relative;aspect-ratio:1;border-radius:8px;overflow:hidden;border:2.5px solid '+(ch?'var(--red)':'var(--bd)')+';cursor:pointer">'
          +'<img src="'+convertImgUrl(u)+'" style="width:100%;height:100%;object-fit:cover" onerror="this.src=\'\'">'
          +'<div style="position:absolute;top:4px;right:4px;width:20px;height:20px;border-radius:50%;background:'+(ch?'var(--red)':'rgba(255,255,255,.7)')+';display:flex;align-items:center;justify-content:center;font-size:12px">'+(ch?'✓':'')+'</div>'
          +'</div>';
      }).join('')
      +'</div>'
      +'<div style="padding:10px 16px 20px;border-top:1px solid var(--bd)">'
      +'<button id="ipc-share" style="width:100%;padding:12px;border:none;border-radius:10px;background:'+(nSel>0?'var(--red)':'#ccc')+';color:#fff;font-size:14px;font-weight:700;cursor:pointer">'
      +(nSel>0?'🖼️ Chia sẻ '+nSel+' ảnh':'Chưa chọn ảnh nào')
      +'</button>'
      +'</div>'
      +'</div>';
    // events
    ov.querySelector('#ipc-close').onclick=function(){ document.body.removeChild(ov); };
    ov.querySelector('#ipc-all').onclick=function(){ sel=sel.map(function(){return true;}); buildUI(); };
    ov.querySelector('#ipc-none').onclick=function(){ sel=sel.map(function(){return false;}); buildUI(); };
    ov.querySelectorAll('[data-i]').forEach(function(el){
      el.onclick=function(){ var i=+el.getAttribute('data-i'); sel[i]=!sel[i]; buildUI(); };
    });
    var shareBtn=ov.querySelector('#ipc-share');
    if(nSel>0) shareBtn.onclick=function(){
      document.body.removeChild(ov);
      _thucHienChiaSe(imgs.filter(function(_,i){return sel[i];}),ma,tenSP);
    };
  }
  buildUI();
  ov.addEventListener('click',function(e){ if(e.target===ov) document.body.removeChild(ov); });
  document.body.appendChild(ov);
}

