var tonKhoChiTiet={};
var tonKhoLoaded=false;
var _tkModalMa=null, _tkModalTen=null;
var TEN_TIER={nhanh:'🟢 Có hàng ngay',mai:'🟡 Hôm nay chuyển – mai có hàng',cho15:'🔴 Chờ 15 ngày'};
var TK_CACHE_KEY='dt_tk_v1', TK_CACHE_TTL=30*60*1000;
function tkLoadingBanner(show){
  var el=document.getElementById('tk-loading-bar');
  if(!el) return;
  el.style.display=show?'flex':'none';
}
function fetchTonKhoChiTiet(){
  var APPS_URL='https://script.google.com/macros/s/AKfycbyrO8symCYOkWsGG0nRWPF7gpndC3mzEVUk15UvWrA0O81ZUumW-kX_gEOZhtCJ34bMVQ/exec';
  // Hiện loading indicator
  tkLoadingBanner(true);
  // Load cache ngay lập tức nếu còn hiệu lực
  try{
    var cached=JSON.parse(localStorage.getItem(TK_CACHE_KEY)||'{}');
    if(cached.ts && cached.data && (Date.now()-cached.ts)<TK_CACHE_TTL){
      tonKhoChiTiet=cached.data;
      tonKhoLoaded=true;
      tkLoadingBanner(false);
      if(typeof render==='function') render();
      if(typeof renderSale==='function') renderSale();
      _refreshTonKhoModalIfOpen();
    }
  }catch(e){}
  // Vẫn fetch GAS để cập nhật mới nhất (chạy nền)
  var cbName='_onTonKhoChiTiet';
  window[cbName]=function(res){
    if(res && res.status==='ok' && res.data){
      tonKhoChiTiet=res.data;
      try{ localStorage.setItem(TK_CACHE_KEY,JSON.stringify({ts:Date.now(),data:res.data})); }catch(e){}
      tkLoadingBanner(false);
      if(typeof render==='function') render();
      if(typeof renderSale==='function') renderSale();
    }
    tonKhoLoaded=true;
    _refreshTonKhoModalIfOpen();
    var s=document.getElementById('_tkct_script');
    if(s) s.remove();
  };
  var old=document.getElementById('_tkct_script');
  if(old) old.remove();
  var s=document.createElement('script');
  s.id='_tkct_script';
  s.src=APPS_URL+'?action=getTonKhoChiTiet&callback='+cbName;
  s.onerror=function(){ tkLoadingBanner(false); s.remove(); };
  document.head.appendChild(s);
}

