    +(Object.keys(thuocTinhMap).length===0?'<p style="font-size:12px;color:#888;margin-bottom:10px">Chưa tải được dữ liệu thuộc tính, vui lòng thử lại sau vài giây.</p>':'')
    +'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:6px 12px">'+body+'</div>'
    +'<div style="display:flex;gap:8px;margin-top:6px">'
