    +'<button onclick="apDungLocNangCao(\''+tab+'\')" style="flex:1;padding:11px;border:none;border-radius:var(--r8);background:#C0232A;color:#fff;font-size:13px;font-weight:700;cursor:pointer;font-family:var(--f)">Áp dụng</button>'
