// Badge gọn hiện trên thẻ sản phẩm — 3 chấm màu theo tốc độ giao, không cần bấm vào
function timTonKho(ma){
  if(!tonKhoChiTiet) return null;
  var tk=tonKhoChiTiet[normMa(ma)]||tonKhoChiTiet[ma];
  if(!tk){
    var k=Object.keys(tonKhoChiTiet).find(function(key){return normMa(key)===normMa(ma);});
    tk=k?tonKhoChiTiet[k]:null;
  }
  return tk;
}
// Nếu tài khoản được gán "Kho phụ trách" (cột trong tab Users, ngăn cách bởi
// dấu phẩy) → chỉ trả về tồn kho của đúng (các) kho đó, tự tính lại tổng/tier.
// Tài khoản không gán gì (admin/nv mặc định) vẫn thấy tất cả như cũ.
function timTonKhoTheoQuyen(ma){
  var tk=timTonKho(ma);
  if(!tk) return tk;
  var sess=checkSession();
  var khoPT=(sess&&sess.khoPhuTrach||'').trim();
  if(!khoPT) return tk;
  var dsKho=khoPT.split(',').map(function(s){return normMa(s);}).filter(Boolean);
  if(!dsKho.length) return tk;
  var khoLoc=tk.kho.filter(function(k){
    var nk=normMa(k.ten);
    return dsKho.some(function(d){return nk.indexOf(d)>=0||d.indexOf(nk)>=0;});
  });
  var tier={nhanh:0,mai:0,cho15:0}, tong=0;
  khoLoc.forEach(function(k){ tier[k.tier]=(tier[k.tier]||0)+k.tong; tong+=k.tong; });
  return {tong:tong, dvt:tk.dvt, tier:tier, kho:khoLoc};
}
// Quy đổi thùng → m² cho Gạch (theo quy cách m²/thùng) — Kính/Ngói/Keo không quy đổi
// vì đơn vị bán khác (Kính bán thẳng theo thùng, Ngói/Keo theo viên/bao).
function m2PerThungCuaMa(ma){
  var p=DATA.find(function(x){return x.ma===ma;});
  if(!p) return null;
  var qc=getQuyCach(p.kc,p.cat);
  return qc?qc.m2:null;
}
function fmtThung(soLuong, dvt, m2pt){
  var s=Math.round(soLuong).toLocaleString('vi-VN')+' '+(dvt||'thùng');
  if(m2pt>0) s+=' (≈ '+Math.round(soLuong*m2pt).toLocaleString('vi-VN')+' m²)';
  return s;
}
// Khách hàng KHÔNG được thấy tên kho/số lô/số lượng thật — đây là thông tin
// nhạy cảm (đối thủ có thể tạo tài khoản khách để dò tồn kho từng kho/lô).
// Nhân viên + admin vẫn xem đầy đủ như cũ.
function laKhachHang(){
  var sess=checkSession();
  return !sess || sess.role==='khachhang';
}
function laAdmin(){
  var sess=checkSession();
  return sess && sess.role==='admin';
}
// Khách hàng chỉ thấy số thật khi ≤ ngưỡng này, vượt quá thì hiện dạng
// "50+" (giới hạn, không lộ số tồn thật lớn cho đối thủ dò).
var NGUONG_TON_KHACH=50;
function hienThiTonChoKhach(soLuong,dvt,m2pt){
  if(soLuong<=NGUONG_TON_KHACH) return fmtThung(soLuong,dvt,m2pt);
  return NGUONG_TON_KHACH+'+ '+(dvt||'thùng');
}
// Dùng cho card danh sách: nhân viên thấy số thật, khách hàng thấy giới hạn + ghi chú
function fmtTkCard(tong, dvt){
  var t=Math.floor(tong);
  if(!laKhachHang()) return t.toLocaleString('vi-VN')+' '+(dvt||'thùng');
  if(t<=NGUONG_TON_KHACH) return t+' '+(dvt||'thùng');
  return NGUONG_TON_KHACH+'+ '+(dvt||'thùng')+' (liên hệ NVKD)';
}
function tonKhoBadgeHtml(ma){
  var tk=timTonKhoTheoQuyen(ma);
  if(!tk || tk.tong<=0) return '';
  if(laKhachHang()){
    var parts=[];
    if(tk.tier.nhanh>0) parts.push('🟢'+(tk.tier.nhanh<=NGUONG_TON_KHACH?Math.round(tk.tier.nhanh).toLocaleString('vi-VN'):NGUONG_TON_KHACH+'+'));
    if(tk.tier.mai>0)   parts.push('🟡'+(tk.tier.mai<=NGUONG_TON_KHACH?Math.round(tk.tier.mai).toLocaleString('vi-VN'):NGUONG_TON_KHACH+'+'));
    if(tk.tier.cho15>0) parts.push('🔴'+(tk.tier.cho15<=NGUONG_TON_KHACH?Math.round(tk.tier.cho15).toLocaleString('vi-VN'):NGUONG_TON_KHACH+'+'));
    return '<span style="font-size:10px;color:var(--t2);white-space:nowrap">'+parts.join(' · ')+'</span>';
  }
  var parts=[];
  if(tk.tier.nhanh>0) parts.push('🟢'+Math.round(tk.tier.nhanh).toLocaleString('vi-VN'));
  if(tk.tier.mai>0)   parts.push('🟡'+Math.round(tk.tier.mai).toLocaleString('vi-VN'));
  if(tk.tier.cho15>0) parts.push('🔴'+Math.round(tk.tier.cho15).toLocaleString('vi-VN'));
  return '<span style="font-size:10px;color:var(--t2);white-space:nowrap">'+parts.join(' · ')+' '+(tk.dvt||'thùng')+'</span>';
}
// Nếu popup tồn kho đang mở đúng mã lúc dữ liệu tải xong -> tự cập nhật lại nội dung
function _refreshTonKhoModalIfOpen(){
  var modal=document.getElementById('modal-ton-kho');
  if(modal && _tkModalMa){ modal.remove(); moTonKho(_tkModalMa, _tkModalTen); }
}
function moTonKho(ma, tenSP){
  _tkModalMa=ma; _tkModalTen=tenSP;
  var tk=timTonKhoTheoQuyen(ma);
  var m2pt=m2PerThungCuaMa(ma);
  var dvt=(tk&&tk.dvt)||'thùng';
  var khachHang=laKhachHang();
  var modal=document.createElement('div');
  modal.id='modal-ton-kho';
  modal.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px';
  var body, ghiChu;
  if(!tonKhoLoaded){
    body='<p style="font-size:13px;color:#888;text-align:center;padding:20px 0">⏳ Đang tải dữ liệu tồn kho, vui lòng chờ...</p>';
    ghiChu='';
  } else if(!tk || tk.tong<=0){
    body='<p style="font-size:13px;color:#888;text-align:center;padding:20px 0">Hết hàng / chưa có dữ liệu tồn kho cho mã này.</p>';
    ghiChu='';
  } else if(khachHang){
    // Khách hàng: KHÔNG hiện tổng toàn quốc. Thấy tên kho + số lượng thật
    // nếu ≤50, vượt quá thì hiện dạng "50+" (giới hạn, không lộ số lớn).
    // Không hiện số lô/màu (chi tiết vận hành nội bộ, dành riêng nhân viên).
    body='';
    ['nhanh','mai','cho15'].forEach(function(tier){
      var khoList=tk.kho.filter(function(k){return k.tier===tier;});
      if(!khoList.length) return;
      body+='<p style="font-size:12px;font-weight:700;margin:10px 0 6px">'+TEN_TIER[tier]+'</p>';
      khoList.forEach(function(k){
        body+='<div style="border:1px solid var(--bd,#eee);border-radius:8px;padding:8px 10px;margin-bottom:6px;display:flex;justify-content:space-between;font-size:13px;font-weight:700">'
          +'<span>'+k.ten+'</span><span>'+hienThiTonChoKhach(k.tong,dvt,m2pt)+'</span></div>';
      });
    });
    ghiChu='<p style="font-size:11px;color:#888;margin-bottom:10px">📞 Số lượng lớn vui lòng liên hệ nhân viên kinh doanh để biết chính xác và tư vấn lô hàng phù hợp: 0819 548 908.</p>';
  } else {
    body='<div style="background:#FDECEA;border-radius:10px;padding:10px 12px;margin-bottom:12px;text-align:center">'
      +'<p style="font-size:12px;color:#888;margin-bottom:2px">Tổng khả dụng toàn quốc</p>'
      +'<p style="font-size:18px;font-weight:800;color:#C0232A;margin:0">'+fmtThung(tk.tong,dvt,m2pt)+'</p></div>';
    ['nhanh','mai','cho15'].forEach(function(tier){
      var khoList=tk.kho.filter(function(k){return k.tier===tier;});
      if(!khoList.length) return;
      body+='<p style="font-size:12px;font-weight:700;margin:10px 0 6px">'+TEN_TIER[tier]+'</p>';
      khoList.forEach(function(k){
        body+='<div style="border:1px solid var(--bd,#eee);border-radius:8px;padding:8px 10px;margin-bottom:6px">'
          +'<div style="display:flex;justify-content:space-between;font-size:13px;font-weight:700;margin-bottom:4px">'
          +'<span>'+k.ten+'</span><span>'+fmtThung(k.tong,dvt,m2pt)+'</span></div>'
          +k.lo.map(function(l){
            return '<div style="display:flex;justify-content:space-between;font-size:11px;color:var(--t2);padding:2px 0">'
              +'<span>Lô '+(l.so_lo||'–')+(l.mau?' · màu '+l.mau:'')+'</span><span>'+fmtThung(l.sl,dvt,m2pt)+'</span></div>';
          }).join('')
          +'</div>';
      });
    });
    ghiChu='<p style="font-size:11px;color:#888;margin-bottom:10px">Mỗi lô là 1 lần sản xuất — nên lấy hết trong 1 lô để tránh lệch màu khi thi công cùng 1 công trình.</p>';
  }
  modal.innerHTML='<div style="background:var(--bg1,#fff);border-radius:14px;max-width:420px;width:100%;max-height:80vh;overflow:auto;padding:16px">'
    +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">'
    +'<p style="font-size:15px;font-weight:700;margin:0">📦 Tồn kho — '+(tenSP||ma)+'</p>'
    +'<button onclick="_tkModalMa=null;document.getElementById(\'modal-ton-kho\').remove()" style="border:none;background:none;font-size:20px;cursor:pointer;line-height:1">×</button>'
    +'</div>'
    +ghiChu
    +body
    +'</div>';
  document.body.appendChild(modal);
}

