    +'<input type="text" id="qltk-password" placeholder="Mật khẩu (để trống nếu không đổi)" style="font-size:13px"/>'
    +'<select id="qltk-role" style="font-size:13px;padding:11px;border:1.5px solid var(--bd2);border-radius:var(--r);background:var(--bg1);font-family:var(--f)">'
    +'<option value="" selected disabled>-- Chọn loại tài khoản --</option>'
