    +'<option value="admin">Admin</option>'
    +'</select>'
    +'<button onclick="luuTaiKhoan()" style="padding:11px;border:none;border-radius:var(--r8);background:#0D47A1;color:#fff;font-size:13px;font-weight:700;cursor:pointer;font-family:var(--f)">💾 Lưu tài khoản</button>'
    +'<p id="qltk-msg" style="font-size:12px;text-align:center;margin-top:4px"></p>'
    +'</div>'
    +'</div>';
  document.body.appendChild(modal);
