function luuTaiKhoan(){
  var APPS_URL='https://script.google.com/macros/s/AKfycbyrO8symCYOkWsGG0nRWPF7gpndC3mzEVUk15UvWrA0O81ZUumW-kX_gEOZhtCJ34bMVQ/exec';
  var u=document.getElementById('qltk-username').value.trim();
  var name=document.getElementById('qltk-name').value.trim();
  var pw=document.getElementById('qltk-password').value;
  var role=document.getElementById('qltk-role').value;
  var msgEl=document.getElementById('qltk-msg');
  if(!u||!name){ msgEl.style.color='#C0232A'; msgEl.textContent='Vui lòng nhập đủ Username và Tên hiển thị!'; return; }
  if(!role){ msgEl.style.color='#C0232A'; msgEl.textContent='Vui lòng chọn loại tài khoản (Khách hàng/Nhân viên/Admin)!'; return; }
  msgEl.style.color='#888'; msgEl.textContent='⏳ Đang lưu...';

  var cbName='_cb_themUser_'+Date.now();
  var s=document.createElement('script');
  var t=setTimeout(function(){
    msgEl.style.color='#C0232A'; msgEl.textContent='❌ Lỗi kết nối, thử lại sau.';
    if(s.parentNode) s.parentNode.removeChild(s);
    delete window[cbName];
  },12000);
  window[cbName]=function(res){
    clearTimeout(t);
    if(s.parentNode) s.parentNode.removeChild(s);
    delete window[cbName];
    if(res && res.status==='ok'){
      msgEl.style.color='#1B5E20'; msgEl.textContent='✅ '+res.msg;
      document.getElementById('qltk-password').value='';
    } else {
      msgEl.style.color='#C0232A'; msgEl.textContent='❌ '+(res?res.msg:'Lỗi không xác định');
    }
  };
  var url=APPS_URL+'?action=themUser'
    +'&username='+encodeURIComponent(u)
    +'&password='+encodeURIComponent(pw)
    +'&name='+encodeURIComponent(name)
    +'&role='+encodeURIComponent(role)
    +'&callback='+encodeURIComponent(cbName);
  s.src=url;
  s.onerror=function(){ clearTimeout(t); msgEl.style.color='#C0232A'; msgEl.textContent='❌ Lỗi kết nối.'; };
  document.head.appendChild(s);
}

// ===== LỊCH SỬ ĐƠN HÀNG =====
var lichSuDonAll=[];
function filterLichSuDon(){
  var q=(document.getElementById('lich-su-don-search').value||'').trim().toLowerCase();
  if(!q){ renderLichSuDon(lichSuDonAll); return; }
  var filtered=lichSuDonAll.filter(function(don){
    return (don.khach||'').toLowerCase().indexOf(q)>=0
        || (don.nguoiLap||'').toLowerCase().indexOf(q)>=0
        || (don.sdt||'').toLowerCase().indexOf(q)>=0;
  });
  renderLichSuDon(filtered);
}
function moLichSuDon(){
  var sess=checkSession();
  if(!sess){alert('Vui lòng đăng nhập lại!');return;}
  var APPS_URL='https://script.google.com/macros/s/AKfycbyrO8symCYOkWsGG0nRWPF7gpndC3mzEVUk15UvWrA0O81ZUumW-kX_gEOZhtCJ34bMVQ/exec';

  var modal=document.createElement('div');
  modal.id='modal-lich-su-don';
  modal.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px';
  modal.innerHTML='<div style="background:var(--bg1,#fff);border-radius:14px;max-width:480px;width:100%;max-height:80vh;overflow:auto;padding:16px">'
    +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">'
    +'<p style="font-size:15px;font-weight:700;margin:0">🕘 Lịch sử đơn hàng</p>'
    +'<button onclick="document.getElementById(\'modal-lich-su-don\').remove()" style="border:none;background:none;font-size:20px;cursor:pointer;line-height:1">×</button>'
    +'</div>'
    +'<input type="text" id="lich-su-don-search" placeholder="🔎 Lọc theo tên khách / người lập..." oninput="filterLichSuDon()" style="font-size:13px;margin-bottom:10px"/>'
    +'<div id="lich-su-don-body" style="font-size:13px;color:#888;text-align:center;padding:20px 0">⏳ Đang tải...</div>'
    +'</div>';
  document.body.appendChild(modal);

  var cbName='_cb_donHang_'+Date.now();
  var s=document.createElement('script');
  var t=setTimeout(function(){ renderLichSuDonError(); },12000);
  window[cbName]=function(res){
    clearTimeout(t);
    if(s.parentNode) s.parentNode.removeChild(s);
    delete window[cbName];
    if(res && res.status==='ok'){ lichSuDonAll=res.data||[]; renderLichSuDon(lichSuDonAll); }
    else { renderLichSuDonError(); }
  };
  s.src=APPS_URL+'?action=getDonHang&username='+encodeURIComponent(sess.user||'')
    +'&role='+encodeURIComponent(sess.role||'nv')+'&callback='+cbName;
  s.onerror=function(){ clearTimeout(t); renderLichSuDonError(); };
  document.head.appendChild(s);
}
function renderLichSuDonError(){
  var body=document.getElementById('lich-su-don-body');
  if(body) body.innerHTML='<p style="color:#C0232A">❌ Không tải được lịch sử đơn. Thử lại sau.</p>';
}
function renderLichSuDon(list){
  var body=document.getElementById('lich-su-don-body');
  if(!body) return;
  if(!list.length){
    body.innerHTML='<p>Chưa có đơn hàng nào.</p>';
    return;
  }
  body.innerHTML=list.map(function(don){
    var tong=(don.items||[]).reduce(function(s,it){return s+(parseFloat(it.thanh)||0);},0);
    var rows=(don.items||[]).map(function(it){
      return '<div style="display:flex;justify-content:space-between;font-size:12px;padding:3px 0;border-bottom:1px dashed #eee">'
        +'<span>'+(it.ma||'')+' · '+(it.kc||'')+' · '+(it.sl||0)+(it.dv||'')+'</span>'
        +'<span>'+(parseFloat(it.thanh)||0).toLocaleString('vi-VN')+'đ</span></div>';
    }).join('');
    return '<div style="border:1px solid var(--bd,#eee);border-radius:10px;padding:10px;margin-bottom:8px">'
      +'<div style="display:flex;justify-content:space-between;font-size:12px;color:#888;margin-bottom:4px">'
      +'<span>'+(don.ngay||'')+'</span><span>'+(don.nguoiLap||'')+'</span></div>'
      +'<p style="font-size:13px;font-weight:700;margin:0 0 6px">'+(don.khach||'')+' · '+(don.sdt||'')+'</p>'
      +rows
      +'<div style="display:flex;justify-content:space-between;font-size:13px;font-weight:700;margin-top:6px;color:#C0232A">'
      +'<span>Tổng</span><span>'+tong.toLocaleString('vi-VN')+'đ</span></div>'
      +'</div>';
  }).join('');
}

function calcAndShowTotals(){
  var totalLe=0,totalNhan=0,totalGiao=0,totalKg=0,coKgChinhXac=false;
  donItems.forEach(function(item){
    var nhanVal, giaoVal;
    var qty_=parseFloat(item.qty)||0;
    var v=tinhSoVien(item);
    if(v&&v.kg){ totalKg+=v.kg; if(v.kgChinhXac) coKgChinhXac=true; }
    if(item.loai==='kinh'){
      // Gạch kính: 3 mức theo số thùng
      if(qty_>=50){ nhanVal=item.nhan3||item.nhan; giaoVal=item.giao3||item.giao; }
      else if(qty_>=21){ nhanVal=item.nhan2||item.nhan; giaoVal=item.giao2||item.giao; }
      else { nhanVal=item.nhan; giaoVal=item.giao; }
    } else if(item.loai==='keo'){
      // Keo/Bột: 2 mức (< 50 bao hoặc ≥ 50 bao)
      if(qty_>=50){ nhanVal=item.nhan2||item.nhan; giaoVal=item.giao2||item.giao; }
      else { nhanVal=item.nhan; giaoVal=item.giao; }
    } else {
      // Gạch / Ngói: dùng giá sale nếu có
      nhanVal=item.ns>0?item.ns:item.nhan;
      giaoVal=item.gs>0?item.gs:item.giao;
    }
    // Tính theo đúng cách hóa đơn VAT: làm tròn giá-trước-VAT từng dòng rồi
    // mới nhân số lượng, thay vì nhân thẳng giá-có-VAT (gây lệch vài đồng).
    totalLe  +=tienHangTruocVAT(item.le||0, item.qty);
    totalNhan+=tienHangTruocVAT(nhanVal||0, item.qty);
    totalGiao+=tienHangTruocVAT(giaoVal||0, item.qty);
  });
  // Cộng VAT 1 lần trên tổng (giống cách hóa đơn thật tính)
  totalLe  =tinhVATvaTongThanhToan(totalLe).tong;
  totalNhan=tinhVATvaTongThanhToan(totalNhan).tong;
  totalGiao=tinhVATvaTongThanhToan(totalGiao).tong;
  var rowKg=document.getElementById('row-total-kg');
  if(rowKg){
    if(totalKg>0){
      rowKg.style.display='flex';
      document.getElementById('don-total-kg').textContent=Math.round(totalKg).toLocaleString('vi-VN')+' kg'+(coKgChinhXac?'':' (ước tính)');
    } else {
      rowKg.style.display='none';
    }
  }
  document.getElementById('don-total-le').textContent=totalLe>0?totalLe.toLocaleString('vi-VN')+'đ':'–';
  // Hiển thị 2 dòng giá ĐL theo hình thức giao
  var rowNhan=document.getElementById('row-total-nhan');
  var rowGiao=document.getElementById('row-total-giao-wrap');
  if(curGiaoHang==='nhan'){
    // Nhận tại kho: hiện nhan, ẩn giao
    document.getElementById('don-total-dl').textContent=totalNhan>0?totalNhan.toLocaleString('vi-VN')+'đ':'–';
    if(rowNhan) rowNhan.style.display='flex';
    if(rowGiao) rowGiao.style.display='none';
  } else {
    // Giao tận nơi: hiện giao, ẩn nhan
    document.getElementById('don-total-dl').textContent=totalGiao>0?totalGiao.toLocaleString('vi-VN')+'đ':'–';
    if(rowNhan) rowNhan.style.display='none';
    if(rowGiao) rowGiao.style.display='flex';
    var donTotalGiao2=document.getElementById('don-total-giao');
    if(donTotalGiao2) donTotalGiao2.textContent=totalGiao>0?totalGiao.toLocaleString('vi-VN')+'đ':'–';
  }
  var vonPhai=curGiaoHang==='nhan'?totalNhan:totalGiao;
  var m=totalLe-vonPhai;
  var pct=totalLe>0?((m/totalLe)*100).toFixed(1):'0.0';
  var lblMargin=document.getElementById('lbl-margin');
  var lblGH=document.getElementById('lbl-giahangh');
  if(lblMargin) lblMargin.textContent='💰 Lợi nhuận ('+(curGiaoHang==='nhan'?'nhận kho':'giao tận nơi')+')';
  if(lblGH) lblGH.textContent='Chi phí vốn ('+(curGiaoHang==='nhan'?'nhận kho':'đi giao')+')';
  document.getElementById('don-margin').textContent=m>0?'+'+m.toLocaleString('vi-VN')+'đ':'–';
  var pctEl=document.getElementById('don-margin-pct');
  if(pctEl) pctEl.textContent=m>0?'Margin: '+pct+'%':'–';
  var box=document.getElementById('don-margin') && document.getElementById('don-margin').closest('div[style*="E8F5E9"]');
  if(box){ box.style.background=m>0?'#E8F5E9':'#FDECEA'; box.style.borderColor=m>0?'#4CAF50':'#C0232A'; }
  return {totalLe:totalLe,totalNhan:totalNhan,totalGiao:totalGiao};
}

function renderDonTotals(){
  calcAndShowTotals();
  apDungPhanQuyenLoi();
}

function clearDon(){
  if(!confirm('Xóa toàn bộ đơn hàng?')) return;
  donItems=[];updateDonBadge();renderDon();
  ['don-ten','don-cty','don-sdt','don-dc','don-note'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});
}

