    +'<tr><td colspan="3" class="h2">Khach: '+ten+' - Nguoi lap: '+nguoi+' - '+gh+'</td></tr>'
    +'</table>';

  h+='<table width="100%" cellspacing="0" cellpadding="0" style="border-collapse:collapse;margin-top:10px">'
    +'<thead><tr>'
